// ═══════════ SCORING PRESETS ═══════════
// Each preset: {win, draw, exact, diff}
// win  = pts for correct result (W/L)
// draw = pts for correct draw
// exact= pts for exact scoreline
// diff = pts for correct goal difference (not exact score)
const PRESETS = {
  standard: {win:1, draw:1, exact:3, diff:2, label:'Estándar (1/1/3/2)'},
  wc:       {win:2, draw:2, exact:5, diff:3, label:'Mundial FIFA (2/2/5/3)'},
  exacto:   {win:0, draw:0, exact:5, diff:0, label:'Solo Exacto (0/0/5/0)'},
  nfl:      {win:3, draw:1, exact:7, diff:4, label:'NFL Style (3/1/7/4)'},
  custom:   {win:1, draw:1, exact:3, diff:2, label:'Personalizado'},
};
let currentPreset = 'wc';

function applyPreset(key) {
  currentPreset = key;
  const p = PRESETS[key];
  document.getElementById('scWin').value   = p.win;
  document.getElementById('scDraw').value  = p.draw;
  document.getElementById('scExact').value = p.exact;
  document.getElementById('scDiff').value  = p.diff;
  document.querySelectorAll('.preset-btn').forEach((b,i) => {
    const keys=['standard','wc','exacto','nfl','custom'];
    b.classList.toggle('active', keys[i]===key);
  });
  updateScoringPreview();
}
function setPreset(key) { currentPreset=key; applyPreset(key); }
function getScoring() {
  return {
    win:   parseInt(document.getElementById('scWin').value)||0,
    draw:  parseInt(document.getElementById('scDraw').value)||0,
    exact: parseInt(document.getElementById('scExact').value)||0,
    diff:  parseInt(document.getElementById('scDiff').value)||0
  };
}
function updateScoringPreview() {
  const s = getScoring();
  document.getElementById('scoringPreview').innerHTML =
    `<strong>Sistema activo:</strong> ` +
    `Aciertas el resultado (G/P): <span style="color:var(--grn)">${s.win} pts</span> &nbsp;·&nbsp; ` +
    `Aciertas el empate: <span style="color:var(--grn)">${s.draw} pts</span> &nbsp;·&nbsp; ` +
    `Marcador exacto: <span style="color:var(--org)">${s.exact} pts</span> &nbsp;·&nbsp; ` +
    `Diferencia exacta: <span style="color:var(--g2)">${s.diff} pts</span>`;
}
applyPreset('wc');

// ═══════════ TIMEZONE ═══════════
const TZ_LABELS = {
  'America/New_York':'ET','America/Chicago':'CT','America/Denver':'MT',
  'America/Los_Angeles':'PT','America/Bogota':'COT','UTC':'UTC'
};
function formatInTz(isoStr, tz) {
  try {
    return new Date(isoStr).toLocaleString('es-CO',{
      timeZone:tz, month:'short', day:'numeric',
      hour:'2-digit', minute:'2-digit', hour12:true
    });
  } catch(e) { return isoStr; }
}
function updateTzPreview() {
  const dt = document.getElementById('mDt').value;
  const tz = document.getElementById('mTz').value;
  if (!dt) return;
  const iso = new Date(dt).toISOString();
  const lines = Object.entries(TZ_LABELS).map(([z,lbl]) =>
    `${lbl}: <strong>${formatInTz(iso,z)}</strong>`
  ).join(' &nbsp;·&nbsp; ');
  document.getElementById('tzPreview').innerHTML = lines;
}

