// ═══════════ PRIZE PREVIEW ═══════════
function updatePrizePreview() {
  const fee  = parseFloat(document.getElementById('pFee').value)||0;
  const p1   = parseFloat(document.getElementById('pr1').value)||0;
  const p2   = parseFloat(document.getElementById('pr2').value)||0;
  const p3   = parseFloat(document.getElementById('pr3').value)||0;
  const com  = parseFloat(document.getElementById('prCom')||{value:0}).value||0;
  const tot  = p1+p2+p3+com;
  const warn = tot>100 ? `<span style="color:var(--red)">⚠ Suma ${tot}% — máximo 100%</span>` : '';
  document.getElementById('prizePreview').innerHTML =
    `Estimado con 10 inscritos (USD ${(fee*10).toFixed(2)} pool):<br>` +
    `<span style="color:var(--org)">◆ 1° → ${(fee*10*p1/100).toFixed(2)}</span> &nbsp;` +
    `<span style="color:var(--g2)">◇ 2° → ${(fee*10*p2/100).toFixed(2)}</span> &nbsp;` +
    `<span style="color:var(--grn)">▸ 3° → ${(fee*10*p3/100).toFixed(2)}</span>` +
    (com ? ` &nbsp;<span style="color:var(--tx2)">Org → ${(fee*10*com/100).toFixed(2)}</span>` : '') + warn;
}
updatePrizePreview();

