// ═══════════ UTILS ═══════════
const ini = n=>n.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase();
const usd = v=>`$${Number(v).toFixed(2)}`;
function fmt(iso,tz){
  if(!iso)return'';
  try{
    return new Date(iso).toLocaleString('es-CO',{
      timeZone:tz||'America/New_York',
      month:'short',day:'numeric',hour:'2-digit',minute:'2-digit',hour12:true
    });
  }catch(e){return new Date(iso).toLocaleDateString('es-CO',{month:'short',day:'numeric',hour:'2-digit',minute:'2-digit'});}
}
function tLeft(d){
  const diff=new Date(d)-new Date(); if(diff<=0)return'Cerrado';
  const h=Math.floor(diff/3600000),m=Math.floor((diff%3600000)/60000);
  return h>24?Math.floor(h/24)+'d '+h%24+'h':h+'h '+m+'m';
}
const empty=t=>`<p style="font-size:10px;color:var(--tx3);padding:5px 0">${t}</p>`;
function avEl(u,cls='av'){
  return u.photo?`<div class="${cls}"><img src="${u.photo}" alt=""></div>`:`<div class="${cls}">${ini(u.name)}</div>`;
}

// ═══════════ SCORING CALCULATOR ═══════════
// Returns {pts, type} given prediction + result + scoring config
function calcPts(ph,pa,rh,ra,sc){
  var ex=(sc&&sc.exact!=null)?sc.exact:5;
  var di=(sc&&sc.diff!=null)?sc.diff:2;
  var wi=(sc&&sc.win!=null)?sc.win:1;
  var dr=(sc&&sc.draw!=null)?sc.draw:1;
  var pw=ph>pa?'H':ph<pa?'A':'D',rw=rh>ra?'H':rh<ra?'A':'D';
  if(ph===rh&&pa===ra)return{pts:ex,type:'exact'};
  if((ph-pa)===(rh-ra)&&pw===rw)return{pts:di,type:'diff'};
  if(pw===rw)return{pts:(rw==='D'?dr:wi),type:'result'};
  return{pts:0,type:'wrong'};
}
function lbRow(u,i,mark){
  const isMe=mark&&CU&&u.id===CU.id;
  const pc=i===0?'p1':i===1?'p2':i===2?'p3':'';
  const sym=i===0?'◆':i===1?'◇':i===2?'▸':i+1;
  return`<div class="lb-r">
    <div class="lb-pos ${pc}">${sym}</div>
    ${avEl(u)}
    <div class="lb-name" style="${isMe?'font-weight:700;color:var(--org)':''}">${u.name}${isMe?' (tú)':''}</div>
    <div><div class="lb-pts">${u.points}</div><div class="lb-ptsl">PTS</div></div>
  </div>`;
}

function matchTeams(m){
  return`<div class="mc-teams">
    <div class="t-blk">
      <div class="t-logo">${m.homeLogo?`<img src="${m.homeLogo}" onerror="this.style.display='none'">`:ini(m.home)}</div>
      <div class="t-nm">${m.home}</div>
    </div>
    <div class="vs">VS</div>
    <div class="t-blk ri">
      <div class="t-logo">${m.awayLogo?`<img src="${m.awayLogo}" onerror="this.style.display='none'">`:ini(m.away)}</div>
      <div class="t-nm">${m.away}</div>
    </div>
  </div>`;
}

function calcPool(pol){
  const paid=DB.users.filter(u=>u.payments&&u.payments.find(p=>p.pollaId===pol.id&&p.status==='succeeded'));
  return paid.length*(pol.fee||0);
}
function calcPrizes(pol){
  const pool=calcPool(pol),pr=pol.prizes||{p1:60,p2:30,p3:10,com:0};
  const inscribed=DB.users.filter(u=>u.payments&&u.payments.find(p=>p.pollaId===pol.id&&p.status==='succeeded')).length;
  return{pool,inscribed,p1:pool*(pr.p1||0)/100,p2:pool*(pr.p2||0)/100,p3:pool*(pr.p3||0)/100,com:pool*(pr.com||0)/100};
}

function prevPh(ev,imgId,ringId){
  const file=ev.target.files[0];if(!file)return;
  const rd=new FileReader();
  rd.onload=e=>{
    const img=document.getElementById(imgId);
    const lbl=document.querySelector('#'+ringId+' .ph-lbl');
    img.src=e.target.result;img.style.display='block';if(lbl)lbl.style.display='none';
  };
  rd.readAsDataURL(file);
}

