function swTab(tab,btn){
  document.querySelectorAll('.tabp').forEach(b=>b.classList.remove('on'));
  btn.classList.add('on');
  document.getElementById('fLogin').classList.toggle('hidden',tab!=='login');
  document.getElementById('fReg').classList.toggle('hidden',tab!=='reg');
  document.getElementById('ae').style.display='none';
  document.getElementById('aok').style.display='none';
}
const showE=m=>{const e=document.getElementById('ae');e.textContent=m;e.style.display='block';setTimeout(()=>e.style.display='none',4500);};
const showOK=m=>{const e=document.getElementById('aok');e.textContent=m;e.style.display='block';setTimeout(()=>e.style.display='none',3000);};

function doLogin(){
  const email=document.getElementById('lEmail').value.trim();
  const pass=document.getElementById('lPass').value;
  if(!email||!pass)return showE('Completa correo y contraseña');
  const u=DB.users.find(x=>x.email===email&&x.pass===pass);
  if(!u)return showE('Correo o contraseña incorrectos');
  CU=u;document.getElementById('S_auth').classList.add('hidden');
  if(u.role==='admin')initAdmin();else initPlayer();
}
function doRegister(){
  const name=document.getElementById('rName').value.trim();
  const email=document.getElementById('rEmail').value.trim();
  const pass=document.getElementById('rPass').value;
  const ph=document.getElementById('rPhPrev').src||'';
  if(!name||!email||!pass)return showE('Completa todos los campos');
  if(pass.length<6)return showE('Contraseña mínimo 6 caracteres');
  if(DB.users.find(u=>u.email===email))return showE('Correo ya registrado');
  DB.users.push({id:DB.nid.u++,name,email,pass,role:'user',points:0,photo:ph.startsWith('data:image')?ph:'',predictions:[],payments:[]});
  showOK('¡Cuenta creada! Ya puedes ingresar.');
  setTimeout(()=>document.querySelector('.tabp').click(),1500);
}
function doLogout(){
  CU=null;
  ['S_admin','S_player'].forEach(id=>document.getElementById(id).classList.add('hidden'));
  document.getElementById('S_auth').classList.remove('hidden');
}

