function saveBanners(){
  saveDB();
  var ok=document.getElementById('bnrOK');
  if(ok){ok.style.display='block';setTimeout(function(){ok.style.display='none';},3000);}
}

function renderAdmBanners(){
  var slots=[{k:'b1',lbl:'Banner 1 — Superior'},{k:'b2',lbl:'Banner 2 — Segunda fila'}];
  var rows='';
  for(var i=0;i<slots.length;i++){
    var k=slots[i].k,lbl=slots[i].lbl,hasImg=DB.banners[k]&&DB.banners[k].length>10;
    rows+='<div class="card" style="margin-bottom:10px">'
      +'<div class="ct"><div class="ct-dot ct-dot-o"></div>'+lbl+'</div>'
      +(hasImg?'<img src="'+DB.banners[k]+'" style="max-width:100%;max-height:90px;border-radius:8px;object-fit:contain;margin-bottom:6px">':'')
      +'<label style="border:2px dashed var(--bd2);border-radius:10px;padding:12px;display:block;text-align:center;cursor:pointer;position:relative">'
      +'<div style="font-size:10px;color:var(--tx3)">'+(hasImg?'✅ Subida — clic para cambiar':'📁 Subir PNG / JPG')+'</div>'
      +'<input type="file" accept="image/*" data-k="'+k+'" style="position:absolute;inset:0;opacity:0;cursor:pointer" onchange="loadBnrFile(event)">'
      +'</label>'
      +(hasImg?'<button class="btn-s" data-k="'+k+'" onclick="removeBnr(this.dataset.k)" style="margin-top:6px;font-size:10px">✕ Quitar</button>':'')
      +'</div>';
  }
  document.getElementById('bnrAdm').innerHTML=rows;
}
function loadBnrFile(e){
  var file=e.target.files[0];if(!file)return;
  var k=e.target.dataset.k;
  var rd=new FileReader();
  rd.onload=function(ev){DB.banners[k]=ev.target.result;applyBanners();renderAdmBanners();saveDB();};
  rd.readAsDataURL(file);
}
function removeBnr(k){DB.banners[k]='';applyBanners();renderAdmBanners();saveDB();}

function applyBanners(){
  [['bnr1Img','bnr1',DB.banners.b1],['bnr2Img','bnr2',DB.banners.b2]].forEach(([imgId,slotId,url])=>{
    const img=document.getElementById(imgId),slot=document.getElementById(slotId);
    if(!img||!slot)return;
    const lbl=slot.querySelector('.bnr-lbl');
    if(url){img.src=url;img.style.display='block';if(lbl)lbl.style.display='none';}
    else{img.style.display='none';if(lbl)lbl.style.display='block';}
  });
}

// ═══════════ SORTABLE USERS TABLE ═══════════
function sortUsers(col){
  if(DB.userSortCol===col){DB.userSortDir=DB.userSortDir==='asc'?'desc':'asc';}
  else{DB.userSortCol=col;DB.userSortDir=col==='name'||col==='email'||col==='role'?'asc':'desc';}
  renderAdmUsers();
}
function renderAdmUsers(){
  const col=DB.userSortCol, dir=DB.userSortDir;
  // Update sort indicators
  ['name','email','points','preds','payments','role'].forEach(c=>{
    const th=document.getElementById('th-'+c);
    if(!th)return;
    th.className=col===c?(dir==='asc'?'sort-asc':'sort-desc'):'';
  });
  const sorted=[...DB.users].sort((a,b)=>{
    let va,vb;
    if(col==='name'){va=a.name.toLowerCase();vb=b.name.toLowerCase();}
    else if(col==='email'){va=a.email.toLowerCase();vb=b.email.toLowerCase();}
    else if(col==='points'){va=a.points;vb=b.points;}
    else if(col==='preds'){va=a.predictions.length;vb=b.predictions.length;}
    else if(col==='payments'){va=(a.payments||[]).filter(p=>p.status==='succeeded').length;vb=(b.payments||[]).filter(p=>p.status==='succeeded').length;}
    else if(col==='role'){va=a.role;vb=b.role;}
    else{va=a.name;vb=b.name;}
    if(va<vb)return dir==='asc'?-1:1;
    if(va>vb)return dir==='asc'?1:-1;
    return 0;
  });
  document.getElementById('admUT').innerHTML=sorted.map(u=>{
    const paid=(u.payments||[]).filter(p=>p.status==='succeeded').length;
    return`<tr>
      <td><div style="display:flex;align-items:center;gap:7px">${avEl(u)} ${u.name}</div></td>
      <td style="color:var(--tx2)">${u.email}</td>
      <td style="font-family:'Kallisto',sans-serif;font-weight:500;color:var(--org)">${u.points}</td>
      <td>${u.predictions.length}</td>
      <td style="color:${paid?'var(--grn)':'var(--tx3)'}">${paid}</td>
      <td><span class="bdg ${u.role==='admin'?'bdg-adm':'bdg-on'}">${u.role}</span></td>
    </tr>`;
  }).join('');
}

