function pTab(tab,btn){
  document.querySelectorAll('#S_player .stab').forEach(t=>t.classList.remove('on'));
  btn.classList.add('on');
  ['inicio','pollas','ranking','historial','perfil','inscripcion','especiales'].forEach(t=>{
    var el=document.getElementById('P_'+t);
    if(el)el.classList.toggle('hidden',t!==tab);
  });
  const map={inicio:renderPInicio,pollas:renderPPollas,ranking:renderPRanking,historial:renderPHist,perfil:renderPPerfil,inscripcion:renderPInscripcion,especiales:renderPEspeciales};
  if(map[tab])map[tab]();
}

