function renderPInscripcion(){
  const open=DB.pollas.filter(p=>p.status==='open');
  document.getElementById('payPolla').innerHTML=open.map(p=>`<option value="${p.id}">${p.name} — ${usd(p.fee)}</option>`).join('')||'<option>Sin pollas abiertas</option>';
  updatePayPreview();
  if(DB.stripe.pub&&typeof Stripe!=='undefined'){
    try{
      if(!stripeInst)stripeInst=Stripe(DB.stripe.pub);
      if(!cardEl){
        const els=stripeInst.elements();
        cardEl=els.create('card',{style:{base:{color:'#efefef',fontFamily:"'Poppins',sans-serif",fontSize:'13px','::placeholder':{color:'#444'}}}});
        cardEl.mount('#card-element');
        cardEl.on('change',e=>document.getElementById('card-errors').textContent=e.error?e.error.message:'');
      }
    }catch(e){}
  }else{
    document.getElementById('card-element').innerHTML='<p style="font-size:10px;color:var(--tx3);padding:7px 0">Configura Stripe Publishable Key en Admin → Stripe para activar cobros.</p>';
  }
}
function updatePayPreview(){
  const id=parseInt(document.getElementById('payPolla')?.value);
  const pol=DB.pollas.find(p=>p.id===id);if(!pol)return;
  const prz=calcPrizes(pol);
  const ya=CU.payments&&CU.payments.find(p=>p.pollaId===id&&p.status==='succeeded');
  document.getElementById('payPreview').innerHTML=`
    <div class="pmg">
      <div class="pmg-item"><div class="pmg-v c-o">${usd(pol.fee)}</div><div class="pmg-l">Inscripción</div></div>
      <div class="pmg-item"><div class="pmg-v c-g">${prz.inscribed}</div><div class="pmg-l">Inscritos</div></div>
      <div class="pmg-item"><div class="pmg-v c-r">${usd(prz.pool)}</div><div class="pmg-l">Pool actual</div></div>
    </div>
    ${ya?`<div class="res-correct">✅ Ya estás inscrito en esta polla</div>`:''}
    ${prz.pool>0?`<div style="font-size:10px;color:var(--tx2);padding:8px 10px;background:var(--bg3);border-radius:8px;border:1px solid var(--bd)">
      Premios estimados: <span style="color:var(--org)">1° ${usd(prz.p1)}</span> · <span style="color:var(--g2)">2° ${usd(prz.p2)}</span> · <span style="color:var(--grn)">3° ${usd(prz.p3)}</span>
    </div>`:''}`;
}
async function submitPayment(){
  if(!stripeInst||!cardEl)return;
  document.getElementById('payBtn').textContent='Procesando...';
  try{
    const {paymentMethod,error}=await stripeInst.createPaymentMethod('card',cardEl);
    if(error){document.getElementById('card-errors').textContent=error.message;}
    else{
      const pollaId=parseInt(document.getElementById('payPolla').value);
      const pol=DB.pollas.find(p=>p.id===pollaId);
      if(!CU.payments)CU.payments=[];
      CU.payments.push({id:Date.now(),pollaId,amount:pol?.fee||0,pmId:paymentMethod.id,date:new Date().toISOString(),status:'succeeded'});
      const ok=document.getElementById('payOK');
      ok.textContent=`✅ ¡Inscrito en "${pol?.name||''}"!`;ok.style.display='block';
      updatePayPreview();
    }
  }catch(e){document.getElementById('payER').textContent='Error al procesar';document.getElementById('payER').style.display='block';}
  document.getElementById('payBtn').textContent='PAGAR INSCRIPCIÓN';
}

// ═══════════ PREDICTION MODAL ═══════════
function openModal(pollaId){
  const pol=DB.pollas.find(p=>p.id===pollaId);if(!pol)return;
  activePolla=pollaId;
  document.getElementById('modTitle').textContent=pol.name;
  const prz=calcPrizes(pol),sc=pol.scoring||{win:1,draw:1,exact:3,diff:2};
  const ms=DB.matches.filter(m=>m.pollaId===pollaId),now=new Date();

  document.getElementById('modMeta').innerHTML=`
    <div class="pmg-item"><div class="pmg-v c-o">${sc.exact}</div><div class="pmg-l">Pts Exacto</div></div>
    <div class="pmg-item"><div class="pmg-v c-g">${prz.inscribed}</div><div class="pmg-l">Inscritos</div></div>
    <div class="pmg-item"><div class="pmg-v c-r">${usd(prz.pool)}</div><div class="pmg-l">Pool USD</div></div>`;

  document.getElementById('modScLegend').innerHTML=`
    <div class="scl-item">Resultado correcto<span class="scl-pts">${sc.win}pts</span></div>
    <div class="scl-item">Empate correcto<span class="scl-pts">${sc.draw}pts</span></div>
    <div class="scl-item">Diferencia exacta<span class="scl-pts">${sc.diff}pts</span></div>
    <div class="scl-item" style="border-color:var(--org3)">Marcador exacto<span class="scl-pts">${sc.exact}pts</span></div>`;

  document.getElementById('modBody').innerHTML=ms.map(m=>{
    const locked=matchIsLocked(m); // 2h before kickoff
    const closed=locked||m.result;
    const lockLabel=locked&&!m.result?timeUntilLock(m):'';
    const pr=CU.predictions.find(p=>p.matchId===m.id);
    const tz=m.tz||pol.tz||'America/New_York';
    const stg=STAGE_LABELS[m.stage]||'';
    return`<div class="mc" style="margin-bottom:11px">
      <div class="mc-hdr">
        <div style="display:flex;align-items:center;gap:5px;flex-wrap:wrap">
          ${stg?`<span class="stage-badge ${STAGE_CSS[m.stage]||'stage-league'}">${stg}</span>`:''}
          ${m.round?`<span style="font-size:9px;color:var(--tx2)">${m.round}</span>`:''}
        </div>
        <div class="mc-time">
          <div class="date-main">${fmt(m.date,tz)}</div>
          <div class="date-tz">${TZ_LABELS[tz]||tz}</div>
        </div>
      </div>
      ${matchTeams(m)}
      ${m.result?
        `<div class="${pr&&pr.pts>0?'res-correct':'res-wrong'}">
          ${m.result.home} — ${m.result.away}
          ${pr?` · ${pr.pts>0?`✅ +${pr.pts} pts (${pr.type||''})`:'❌ 0 pts'}`:''}
        </div>`:
        closed?`<div class="res-pending">${pr?`Tu predicción: ${pr.home}–${pr.away}`:locked&&!m.result?`🔒 ${lockLabel}`:'Sin predicción (cerrado)'}</div>`:
        `<div class="sc-row">
          <input class="sc-inp" id="ph_${m.id}" type="number" min="0" value="${pr?pr.home:''}" placeholder="0">
          <div class="sc-sep">—</div>
          <input class="sc-inp" id="pa_${m.id}" type="number" min="0" value="${pr?pr.away:''}" placeholder="0">
        </div>`
      }
    </div>`;
  }).join('');
  document.getElementById('predModal').style.display='block';
}
function closeModal(){document.getElementById('predModal').style.display='none';activePolla=null;}

// ════ MATCH CUTOFF ════
function matchIsLocked(m){
  if(!m.date)return false;
  if(m.result)return true; // already has result
  var kickoff=new Date(m.date).getTime();
  var now=Date.now();
  return now >= kickoff - (2*60*60*1000); // 2 hours before
}
function timeUntilLock(m){
  if(!m.date)return '';
  var kickoff=new Date(m.date).getTime();
  var diff=kickoff-(2*60*60*1000)-Date.now();
  if(diff<=0)return '🔒 Cerrado';
  var h=Math.floor(diff/3600000);
  var min=Math.floor((diff%3600000)/60000);
  if(h>24){var d=Math.floor(h/24);return 'Cierra en '+d+'d '+(h%24)+'h';}
  if(h>0)return 'Cierra en '+h+'h '+min+'m';
  return 'Cierra en '+min+'m';
}

function savePreds(){
  if(!activePolla)return;
  const ms=DB.matches.filter(m=>m.pollaId===activePolla);
  const now=new Date();let saved=0;
  ms.forEach(m=>{
    const ct=new Date(new Date(m.date).getTime()-3600000);
    if(now>ct||m.result)return;
    const h=document.getElementById('ph_'+m.id),a=document.getElementById('pa_'+m.id);
    if(!h||!a||h.value===''||a.value==='')return;
    const pr={matchId:m.id,pollaId:activePolla,home:parseInt(h.value),away:parseInt(a.value),pts:0,correct:false,type:'pending'};
    const idx=CU.predictions.findIndex(p=>p.matchId===m.id);
    if(idx>=0)CU.predictions[idx]=pr;else CU.predictions.push(pr);
    saved++;
  });
  closeModal();renderPInicio();
  if(saved)alert(`✅ ${saved} predicción(es) guardada(s)`);
  else alert('No hay predicciones nuevas o los partidos ya cerraron');
}

