// ════ PERSISTENCE ════
function lsSave(){try{localStorage.setItem('cfl_db',JSON.stringify(DB));}catch(e){}}
function lsLoad(){try{var r=localStorage.getItem('cfl_db');return r?JSON.parse(r):null;}catch(e){return null;}}
async function saveDB(){lsSave();if(window._fbSave)window._fbSave(DB).catch(function(){});}
async function fbSync(){
  try{
    if(!window._fbLoad)return;
    var d=await window._fbLoad();
    if(d&&d.users&&d.users.length){
      DB.users=d.users;DB.pollas=d.pollas||[];DB.matches=d.matches||[];
      DB.banners=d.banners||{b1:'',b2:''};DB.stripe=d.stripe||{pub:'',secret:''};
      DB.nid=d.nid||{u:10,p:1,m:1};
      DB.bonusQuestions=d.bonusQuestions||[];
      DB.specials=d.specials&&d.specials.length?d.specials:[];
      // Always seed missing data and push back to Firebase
      var changed=false;
      if(!DB.pollas.some(function(p){return p.name&&p.name.indexOf('World Cup 2026')>-1;})){
        seedWC2026();changed=true;
      }
      if(!DB.specials.length){
        seedWC2026Specials();changed=true;
      }
      if(changed&&window._fbSave)window._fbSave(DB).catch(function(){});
      lsSave();
      var auth=document.getElementById('S_auth');
      if(typeof CU!=='undefined'&&CU&&auth&&auth.classList.contains('hidden')){
        CU=DB.users.find(function(u){return u.id===CU.id;})||CU;
        try{if(CU.role==='admin')renderAdmDash();else renderPInicio();}catch(e){}
      }
    }else if(window._fbSave){
      // No cloud data — push everything including specials
      seedWC2026();seedWC2026Specials();
      window._fbSave(DB).catch(function(){});
    }
  }catch(e){console.warn('fbSync:',e);}
}

