function renderAdmBonus(){
  var el=document.getElementById('admBonusList');if(!el)return;
  var bqs=DB.bonusQuestions||[];
  el.innerHTML=bqs.length?bqs.map(function(bq){
    var pol=DB.pollas.find(function(p){return p.id===bq.pollaId;});
    return'<div class="mc" style="margin-bottom:8px"><div class="mc-hdr"><div>'
      +'<div style="font-size:11px;font-weight:600">'+bq.question+'</div>'
      +'<div style="font-size:9px;color:var(--tx3)">'+(pol?pol.name:'Global')+' · +'+bq.pts+' pts</div>'
      +(bq.answer?'<div style="font-size:9px;color:var(--grn)">✅ '+bq.answer+'</div>':'')
      +'</div><div style="display:flex;gap:5px">'
      +(bq.answer?'':'<button class="btn-xs" onclick="promptBonusAnswer('+bq.id+')">Set Answer</button>')
      +'<button class="btn-xs" style="background:var(--red2);color:var(--red)" onclick="deleteBonus('+bq.id+')">✕</button>'
      +'</div></div></div>';
  }).join(''):'<p style="font-size:10px;color:var(--tx3)">No hay preguntas bonus</p>';
}
function createBonus(){
  var q=(document.getElementById('bqQ')||{}).value;
  var pts=parseInt((document.getElementById('bqPts')||{}).value)||10;
  var pollaId=parseInt((document.getElementById('bqPolla')||{}).value)||0;
  if(!q||!q.trim()){alert('Escribe la pregunta');return;}
  if(!DB.bonusQuestions)DB.bonusQuestions=[];
  DB.bonusQuestions.push({id:Date.now(),pollaId:pollaId,question:q.trim(),pts:pts,answer:null,userAnswers:[]});
  document.getElementById('bqQ').value='';
  renderAdmBonus();saveDB();
}
function deleteBonus(id){
  DB.bonusQuestions=(DB.bonusQuestions||[]).filter(function(b){return b.id!==id;});
  renderAdmBonus();saveDB();
}
function promptBonusAnswer(id){
  var bq=(DB.bonusQuestions||[]).find(function(b){return b.id===id;});if(!bq)return;
  var ans=prompt('Correct answer for:\n"'+bq.question+'"');
  if(ans===null||!ans.trim())return;
  bq.answer=ans.trim();
  (bq.userAnswers||[]).forEach(function(ua){
    if(ua.answer.toLowerCase()===ans.trim().toLowerCase()){
      var u=DB.users.find(function(x){return x.id===ua.userId;});
      if(u)u.points=(u.points||0)+bq.pts;
    }
  });
  renderAdmBonus();saveDB();alert('✅ Points awarded!');
}
function submitBonusAnswer(bqId){
  var el=document.getElementById('bqAns_'+bqId);
  if(!el||!el.value.trim()){alert('Enter your answer');return;}
  var bq=(DB.bonusQuestions||[]).find(function(b){return b.id===bqId;});if(!bq)return;
  if(!bq.userAnswers)bq.userAnswers=[];
  var ex=bq.userAnswers.find(function(a){return a.userId===CU.id;});
  if(ex)ex.answer=el.value.trim();else bq.userAnswers.push({userId:CU.id,answer:el.value.trim()});
  saveDB();alert('✅ Guardado!');
}

// ════ STATS TAB ════
function renderPStats(){
  var el=document.getElementById('P_stats');if(!el)return;
  var done=DB.matches.filter(function(m){return m.result;});
  var out='';
  if(!done.length){out='<div class="card"><p style="text-align:center;color:var(--tx3);padding:20px;font-size:10px">No results yet</p></div>';}
  else{
    var tot=0,ex=0,di=0,re=0,wr=0;
    DB.users.forEach(function(u){if(u.role==='admin')return;(u.predictions||[]).forEach(function(p){if(!done.find(function(m){return m.id===p.matchId;}))return;tot++;if(p.type==='exact')ex++;else if(p.type==='diff')di++;else if(p.type==='result')re++;else wr++;});});
    out+='<div class="card"><div class="ct"><div class="ct-dot ct-dot-o"></div>Accuracy</div>';
    if(tot>0){out+='<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:10px">';[{l:'Exact',v:ex,c:'var(--org)'},{l:'Diff',v:di,c:'#5a82f0'},{l:'Result',v:re,c:'var(--grn)'},{l:'Miss',v:wr,c:'var(--tx3)'}].forEach(function(s){out+='<div style="text-align:center;padding:9px;background:var(--bg3);border-radius:8px"><div style="font-size:20px;font-weight:700;color:'+s.c+'">'+Math.round(s.v/tot*100)+'%</div><div style="font-size:9px;color:var(--tx3)">'+s.l+'</div></div>';});out+='</div>';}
    out+='</div><div class="card"><div class="ct"><div class="ct-dot ct-dot-g"></div>Per Match</div>';
    done.forEach(function(m){var preds=[];DB.users.forEach(function(u){if(u.role==='admin')return;var p=(u.predictions||[]).find(function(x){return x.matchId===m.id;});if(p)preds.push(p);});if(!preds.length)return;var H=preds.filter(function(p){return p.home>p.away;}).length,D=preds.filter(function(p){return p.home===p.away;}).length,A=preds.filter(function(p){return p.home<p.away;}).length,n=preds.length,act=m.result.home>m.result.away?'H':m.result.home<m.result.away?'A':'D';out+='<div style="padding:7px 0;border-bottom:1px solid var(--bd)"><div style="display:flex;justify-content:space-between;margin-bottom:3px"><span style="font-size:11px">'+m.home+' '+m.result.home+'-'+m.result.away+' '+m.away+'</span><span style="font-size:9px;color:var(--tx3)">'+n+' pred.</span></div><div style="display:flex;gap:10px;font-size:10px"><span style="color:'+(act==='H'?'var(--grn)':'var(--tx3)')+'">H '+Math.round(H/n*100)+'%</span><span style="color:'+(act==='D'?'var(--grn)':'var(--tx3)')+'">X '+Math.round(D/n*100)+'%</span><span style="color:'+(act==='A'?'var(--grn)':'var(--tx3)')+'">A '+Math.round(A/n*100)+'%</span></div></div>';});
    out+='</div>';
  }
  var bqs=(DB.bonusQuestions||[]).filter(function(bq){return!bq.answer;});
  if(bqs.length){out+='<div class="card"><div class="ct"><div class="ct-dot" style="background:#b450f0;width:8px;height:8px;border-radius:50%;flex-shrink:0"></div>Bonus</div>';bqs.forEach(function(bq){var my=(bq.userAnswers||[]).find(function(a){return a.userId===CU.id;});out+='<div style="padding:10px;background:var(--bg3);border-radius:8px;margin-bottom:8px"><div style="font-size:9px;font-weight:700;letter-spacing:2px;color:#b450f0;margin-bottom:4px">BONUS +'+bq.pts+' PTS</div><div style="font-size:12px;font-weight:600;margin-bottom:8px">'+bq.question+'</div>'+(my?'<div style="font-size:10px;color:var(--grn)">✅ '+my.answer+'</div>':'<div style="display:flex;gap:6px"><input class="fi" id="bqAns_'+bq.id+'" placeholder="Your answer" style="flex:1;padding:7px 10px;font-size:11px"><button class="btn btn-p" onclick="submitBonusAnswer('+bq.id+')" style="padding:7px 12px;font-size:10px">Submit</button></div>')+'</div>';});out+='</div>';}
  el.innerHTML=out;
}


// ════ ÍTEMS ESPECIALES ════
function getSpecials(pollaId){
  return(DB.specials||[]).filter(function(s){return s.pollaId===pollaId;})
    .sort(function(a,b){return(a.orden||0)-(b.orden||0);});
}

function getPollaTeams(pollaId){
  // Get unique teams from matches in this polla
  var teams=[];
  (DB.matches||[]).filter(function(m){return m.pollaId===pollaId;}).forEach(function(m){
    if(m.home&&m.home!=='TBD'&&teams.indexOf(m.home)===-1)teams.push(m.home);
    if(m.away&&m.away!=='TBD'&&teams.indexOf(m.away)===-1)teams.push(m.away);
  });
  return teams.sort();
}

function updateSpEquipos(){
  var pollaId=parseInt(document.getElementById('spPolla').value);
  var teams=getPollaTeams(pollaId);
  var wrap=document.getElementById('spEquiposWrap');
  if(!wrap)return;
  if(teams.length){
    wrap.innerHTML=teams.map(function(t){
      return'<button type="button" class="team-chip" onclick="pickTeam(this)" data-team="'+t+'">'+t+'</button>';
    }).join('');
  }else{
    wrap.innerHTML='<span style="font-size:9px;color:var(--tx3)">No hay equipos confirmados en esta polla aún</span>';
  }
}

function pickTeam(btn){
  // Fill the desc field with the team name as a hint
  var opts=document.getElementById('spOpciones');
  if(!opts)return;
  // Add to options field
  var cur=opts.value.split(',').map(function(x){return x.trim();}).filter(Boolean);
  var t=btn.dataset.team;
  if(cur.indexOf(t)===-1){cur.push(t);}
  else{cur=cur.filter(function(x){return x!==t;});}
  opts.value=cur.join(', ');
  // Toggle visual
  btn.classList.toggle('active',cur.indexOf(t)>-1);
}

function renderAdmEspeciales(){
  var sel=document.getElementById('spPolla');
  if(sel){
    if(!DB.pollas.length){
      sel.innerHTML='<option value="">— Primero crea una polla —</option>';
    }else{
      sel.innerHTML=DB.pollas.map(function(p){
        return'<option value="'+p.id+'">'+p.name+'</option>';
      }).join('');
      updateSpEquipos();
    }
  }
  var el=document.getElementById('spList');if(!el)return;
  var all=DB.specials||[];
  if(!all.length){
    el.innerHTML='<p style="font-size:10px;color:var(--tx3);padding:8px 0">No hay ítems especiales aún</p>';
    return;
  }
  // Group by polla
  var byPolla={};
  all.forEach(function(s){
    if(!byPolla[s.pollaId])byPolla[s.pollaId]=[];
    byPolla[s.pollaId].push(s);
  });
  var out='';
  Object.keys(byPolla).forEach(function(pid){
    var pol=DB.pollas.find(function(p){return p.id===parseInt(pid);});
    out+='<div style="margin-bottom:14px">'
      +'<div style="font-size:9px;font-weight:700;letter-spacing:2px;color:var(--org);text-transform:uppercase;margin-bottom:6px">'+(pol?pol.name:'Polla #'+pid)+'</div>';
    byPolla[pid].sort(function(a,b){return(a.orden||0)-(b.orden||0);}).forEach(function(s){
      var isOpen=s.status!=='closed';
      var answered=(s.userAnswers||[]).length;
      out+='<div class="mc" style="margin-bottom:6px">'
        +'<div class="mc-hdr" style="flex-wrap:wrap;gap:8px">'
        // Left side
        +'<div style="flex:1;min-width:0">'
        +'<div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap">'
        +'<span style="font-size:11px;font-weight:700;color:var(--tx)">'+s.name+'</span>'
        +'<span style="font-size:9px;background:var(--org2);color:var(--org);border-radius:8px;padding:2px 8px;font-weight:700">+'+s.pts+' pts</span>'
        +'<span style="font-size:9px;padding:2px 8px;border-radius:8px;font-weight:700;background:'+(isOpen?'var(--grn2)':'rgba(255,60,60,.1)')+';color:'+(isOpen?'var(--grn)':'var(--red)')+';">'+(isOpen?'🟢 Activo':'🔴 Cerrado')+'</span>'
        +(s.answer?'<span style="font-size:9px;background:var(--grn2);color:var(--grn);border-radius:8px;padding:2px 8px">✅ '+s.answer+'</span>':'')
        +'</div>'
        +'<div style="font-size:9px;color:var(--tx3);margin-top:3px">'+s.desc+'</div>'
        +(s.opciones&&s.opciones.length?'<div style="font-size:9px;color:var(--tx3);margin-top:2px">Opciones: '+s.opciones.join(', ')+'</div>':'')
        +'<div style="font-size:9px;color:var(--tx3);margin-top:2px">'+answered+' respuesta(s)</div>'
        +'</div>'
        // Right side — actions
        +'<div style="display:flex;flex-direction:column;gap:4px;align-items:flex-end">'
        +'<button class="btn-xs" onclick="toggleEspecial('+s.id+')" style="background:'+(isOpen?'rgba(255,60,60,.1)':'var(--grn2)')+';color:'+(isOpen?'var(--red)':'var(--grn)')+';">'+(isOpen?'🔴 Cerrar':'🟢 Abrir')+'</button>'
        +(s.answer?'':'<button class="btn-xs" onclick="setSpecialAnswer('+s.id+')">✅ Fijar resp.</button>')
        +'<button class="btn-xs" onclick="editSpecial('+s.id+')">✏️</button>'
        +'<button class="btn-xs" style="background:var(--red2);color:var(--red)" onclick="deleteSpecial('+s.id+')">✕</button>'
        +'</div>'
        +'</div></div>';
    });
    out+='</div>';
  });
  el.innerHTML=out;
}

function createEspecial(){
  var pollaId=parseInt(document.getElementById('spPolla').value);
  var name=document.getElementById('spName').value.trim();
  var pts=parseInt(document.getElementById('spPts').value)||20;
  var status=document.getElementById('spStatus').value;
  var desc=document.getElementById('spDesc').value.trim();
  var opcsRaw=document.getElementById('spOpciones').value;
  var opciones=opcsRaw?opcsRaw.split(',').map(function(x){return x.trim();}).filter(Boolean):[];
  if(!name){alert('Escribe el nombre del ítem');return;}
  if(!desc){alert('Escribe la pregunta o descripción');return;}
  if(!DB.specials)DB.specials=[];
  var orden=(DB.specials.filter(function(s){return s.pollaId===pollaId;}).length)+1;
  DB.specials.push({id:Date.now(),pollaId:pollaId,name:name,desc:desc,pts:pts,status:status,opciones:opciones,answer:null,userAnswers:[],orden:orden});
  document.getElementById('spName').value='';
  document.getElementById('spDesc').value='';
  document.getElementById('spOpciones').value='';
  document.getElementById('spPts').value='20';
  document.querySelectorAll('.team-chip').forEach(function(b){b.classList.remove('active');});
  renderAdmEspeciales();saveDB();
}

function toggleEspecial(id){
  var s=(DB.specials||[]).find(function(x){return x.id===id;});if(!s)return;
  s.status=s.status==='closed'?'open':'closed';
  renderAdmEspeciales();saveDB();
}

function deleteSpecial(id){
  if(!confirm('¿Eliminar este ítem especial?'))return;
  DB.specials=(DB.specials||[]).filter(function(s){return s.id!==id;});
  renderAdmEspeciales();saveDB();
}

function setSpecialAnswer(id){
  var s=(DB.specials||[]).find(function(x){return x.id===id;});if(!s)return;
  var ans;
  if(s.opciones&&s.opciones.length){
    var opts=s.opciones.map(function(o,i){return(i+1)+'. '+o;}).join('\n');
    ans=prompt('Respuesta correcta para:\n"'+s.desc+'"\nOpciones:\n'+opts+'\n\nEscribe la respuesta exacta:');
  }else{
    ans=prompt('Respuesta correcta para: '+s.desc);
  }
  if(ans===null||!ans.trim())return;
  s.answer=ans.trim();
  s.status='closed';
  var awarded=0;
  (s.userAnswers||[]).forEach(function(ua){
    if(ua.answer.trim().toLowerCase()===ans.trim().toLowerCase()){
      var u=DB.users.find(function(x){return x.id===ua.userId;});
      if(u){u.points=(u.points||0)+s.pts;awarded++;}
    }
  });
  renderAdmEspeciales();saveDB();
  alert('✅ Respuesta: "'+s.answer+'" — '+awarded+' jugador(es) ganaron +'+s.pts+' pts');
}

function editSpecial(id){
  var s=(DB.specials||[]).find(function(x){return x.id===id;});if(!s)return;
  var n=prompt('Nombre:',s.name);if(n===null)return;
  var d=prompt('Pregunta:',s.desc);if(d===null)return;
  var p=parseInt(prompt('Puntos:',s.pts));if(isNaN(p))return;
  s.name=n.trim()||s.name;s.desc=d.trim()||s.desc;s.pts=p||s.pts;
  renderAdmEspeciales();saveDB();
}

// ════ PLAYER: VER Y RESPONDER ESPECIALES ════
function renderPEspeciales(){
  var el=document.getElementById('P_spec_content');if(!el)return;
  var openPollas=DB.pollas.filter(function(p){return p.status==='open';});
  if(!openPollas.length){
    el.innerHTML='<div class="card"><p style="text-align:center;padding:20px;font-size:10px;color:var(--tx3)">No hay pollas activas</p></div>';
    return;
  }
  var out='';
  openPollas.forEach(function(pol){
    var items=getSpecials(pol.id).filter(function(s){return s.status!=='closed'||s.answer;});
    if(!items.length)return;
    out+='<div class="card"><div class="ct"><div class="ct-dot ct-dot-o"></div>'+pol.name+'</div>';
    out+='<div style="font-size:9px;color:var(--tx3);margin-bottom:10px">Predicciones especiales — gana puntos extra</div>';
    items.forEach(function(s){
      var myAns=(s.userAnswers||[]).find(function(a){return a.userId===CU.id;});
      var isClosed=s.status==='closed';
      out+='<div style="background:var(--bg3);border-radius:10px;padding:12px;margin-bottom:10px;border:1px solid var(--bd)">';
      // Header
      out+='<div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;margin-bottom:10px">'
        +'<div style="flex:1"><div style="font-size:12px;font-weight:700;color:var(--tx)">'+s.name+'</div>'
        +'<div style="font-size:10px;color:var(--tx3);margin-top:2px">'+s.desc+'</div></div>'
        +'<span style="font-size:11px;font-weight:700;background:var(--org2);color:var(--org);border-radius:20px;padding:3px 10px;white-space:nowrap">+'+s.pts+' pts</span>'
        +'</div>';
      if(isClosed&&s.answer){
        // Result revealed
        var correct=myAns&&myAns.answer.trim().toLowerCase()===s.answer.trim().toLowerCase();
        out+='<div style="padding:10px;border-radius:8px;background:'+(correct?'var(--grn2)':'var(--bg4)')+';border:1px solid '+(correct?'var(--grn3)':'var(--bd2)')+'">'
          +'<div style="font-size:9px;font-weight:700;color:var(--tx3);margin-bottom:4px;letter-spacing:1px">RESULTADO</div>'
          +'<div style="font-size:13px;font-weight:700;color:'+(correct?'var(--grn)':'var(--tx)')+'">'+s.answer+'</div>'
          +(myAns?'<div style="font-size:9px;color:var(--tx3);margin-top:4px">Tu respuesta: '
            +(correct?'<span style="color:var(--grn)">'+myAns.answer+' ✓ +'+s.pts+' pts</span>'
              :'<span style="color:var(--red2)">'+myAns.answer+' ✗</span>')+'</div>'
            :'<div style="font-size:9px;color:var(--tx3);margin-top:4px">No respondiste</div>')
          +'</div>';
      }else if(myAns){
        // Already answered — show with edit option
        out+='<div style="display:flex;justify-content:space-between;align-items:center;background:var(--bg4);border-radius:8px;padding:9px 12px">'
          +'<div><div style="font-size:9px;color:var(--tx3)">Tu predicción</div>'
          +'<div style="font-size:12px;font-weight:600;color:var(--tx)">'+myAns.answer+'</div></div>'
          +'<button class="btn-xs" onclick="editSpecialAnswer('+s.id+')">Cambiar</button>'
          +'</div>';
      }else{
        // Not answered — show options or text input
        if(s.opciones&&s.opciones.length){
          out+='<div style="display:flex;flex-wrap:wrap;gap:6px">';
          s.opciones.forEach(function(o){
            out+='<button class="team-chip" onclick="selectSpecialOption('+s.id+',this.dataset.opt)" data-id="'+s.id+'" data-opt="'+o+'">'+o+'</button>';
          });
          out+='</div>';
        }else{
          out+='<div style="display:flex;gap:8px">'
            +'<input class="fi" id="spAns_'+s.id+'" placeholder="Tu predicción..." style="flex:1;padding:8px 10px;font-size:11px">'
            +'<button class="btn btn-p" onclick="submitSpecialAnswer('+s.id+')" style="padding:8px 14px;font-size:10px;white-space:nowrap">Enviar</button>'
            +'</div>';
        }
      }
      out+='</div>';
    });
    out+='</div>';
  });
  if(!out)out='<div class="card"><p style="text-align:center;padding:20px;font-size:10px;color:var(--tx3)">No hay ítems especiales disponibles</p></div>';
  el.innerHTML=out;
}

function selectSpecialOption(spId,opt){
  var s=(DB.specials||[]).find(function(x){return x.id===spId;});if(!s)return;
  if(!s.userAnswers)s.userAnswers=[];
  var ex=s.userAnswers.find(function(a){return a.userId===CU.id;});
  if(ex)ex.answer=opt;else s.userAnswers.push({userId:CU.id,answer:opt,ts:Date.now()});
  saveDB();renderPEspeciales();
}

function submitSpecialAnswer(spId){
  var el=document.getElementById('spAns_'+spId);
  if(!el||!el.value.trim()){alert('Escribe tu predicción');return;}
  var s=(DB.specials||[]).find(function(x){return x.id===spId;});if(!s)return;
  if(!s.userAnswers)s.userAnswers=[];
  s.userAnswers.push({userId:CU.id,answer:el.value.trim(),ts:Date.now()});
  saveDB();renderPEspeciales();
}

function editSpecialAnswer(spId){
  var s=(DB.specials||[]).find(function(x){return x.id===spId;});if(!s)return;
  var my=(s.userAnswers||[]).find(function(a){return a.userId===CU.id;});if(!my)return;
  if(s.opciones&&s.opciones.length){
    // Clear answer and re-render so they can pick again
    my.answer='';
    saveDB();renderPEspeciales();
  }else{
    var newAns=prompt('Cambiar predicción:\n'+s.desc,my.answer);
    if(newAns===null||!newAns.trim())return;
    my.answer=newAns.trim();my.ts=Date.now();
    saveDB();renderPEspeciales();
  }
}

