// ════ Seed WC2026 specials if missing ════
function seedWC2026Specials(){
  var wcPolla=DB.pollas.find(function(p){return p.name&&p.name.indexOf('World Cup 2026')>-1;});
  if(!wcPolla)return;
  if(!DB.specials)DB.specials=[];
  var pid=wcPolla.id;
  var hasSpecials=DB.specials.some(function(s){return s.pollaId===pid;});
  if(hasSpecials)return;
  var now=Date.now();
  DB.specials.push(
    {id:now+1,pollaId:pid,name:'🏆 Equipo Campeón',desc:'¿Qué equipo ganará el Mundial 2026?',pts:20,status:'open',opciones:[],answer:null,userAnswers:[],orden:1},
    {id:now+2,pollaId:pid,name:'🥈 Equipo Subcampeón',desc:'¿Qué equipo llegará a la Final?',pts:10,status:'open',opciones:[],answer:null,userAnswers:[],orden:2},
    {id:now+3,pollaId:pid,name:'⚽ Mejor Goleador',desc:'¿Quién será el máximo goleador del torneo?',pts:10,status:'open',opciones:[],answer:null,userAnswers:[],orden:3},
    {id:now+4,pollaId:pid,name:'🌟 Balón de Oro',desc:'¿Quién ganará el Balón de Oro del torneo?',pts:10,status:'open',opciones:[],answer:null,userAnswers:[],orden:4},
    {id:now+5,pollaId:pid,name:'🧤 Mejor Portero',desc:'¿Quién ganará el Guante de Oro?',pts:5,status:'open',opciones:[],answer:null,userAnswers:[],orden:5}
  );
  console.log('✅ WC2026 especiales seeded');
}

function startApp(){
  if(window._appStarted)return;
  window._appStarted=true;
  var local=lsLoad();
  if(local&&local.users&&local.users.length){
    DB.users=local.users;DB.pollas=local.pollas||[];DB.matches=local.matches||[];
    DB.banners=local.banners||{b1:'',b2:''};DB.stripe=local.stripe||{pub:'',secret:''};
    DB.nid=local.nid||{u:10,p:1,m:1};DB.bonusQuestions=local.bonusQuestions||[];DB.specials=local.specials||[];
    seedWC2026();        // adds WC polla if missing
    seedWC2026Specials(); // adds specials if missing
    lsSave();
  }else{
    seedWC2026();
    seedWC2026Specials();
    lsSave();
    if(window._fbSave)window._fbSave(DB);
  }
  initLang();initTheme();
  setTimeout(fbSync,1000);
}
document.addEventListener('DOMContentLoaded',startApp);
document.addEventListener('firebase-ready',function(){setTimeout(fbSync,300);});
setTimeout(function(){if(!window._appStarted)startApp();},500);
setInterval(function(){if(typeof CU!=='undefined'&&CU&&CU.role!=='admin'){try{renderPInicio();}catch(e){}}},60000);
